    dp = [0, INF, INF, INF]
    target = "ABBA"
    for ch in s:
        nd = [INF] * 4
        for st in range(4):
            if dp[st] == INF:
                continue
            if dp[st] + 1 < nd[st]:
                nd[st] = dp[st] + 1
            if ch == target[st]:
                nxt = st + 1
                if nxt < 4:
                    if dp[st] < nd[nxt]:
                        nd[nxt] = dp[st]
            else:
                if dp[st] < nd[st]:
                    nd[st] = dp[st]
        dp = nd
    return min(dp)

