def entry(lo, hi, M):
    def count_upto(N):
        if N<0: return 0
        s=str(N)
        L=len(s)
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def dp(i, rem, tight, started):
            if i==L:
                return 1 if (rem % M)==0 else 0
            hi_d = int(s[i]) if tight else 9
            total=0
            for d in range(0, hi_d+1):
                nt = tight and (d==hi_d)
                ns = started or (d>0)
                exp=L-1-i
                sign = 1 if exp%2==0 else -1
                nrem = (rem + sign*d) % M
                total += dp(i+1, nrem, nt, ns)
            return total
        return dp(0,0,True,False)
    return count_upto(hi)-count_upto(lo-1)

